  for (let i = 0; i < M; ++i) B[i] = Number(input[idx++]);
  A.sort((a, b) => a - b);
  B.sort((a, b) => a - b);
  let i = 0, j = 0;
  const merged = [];
  while (i < N && j < M) {
    if (A[i] <= B[j]) merged.push(A[i++]);
